mapper.select:
SELECT COUNT(*) FROM doctor d INNER JOIN doctor_audit da ON d.id = da.doctor_id LEFT JOIN department dept ON d.department_id = dept.id WHERE d.status = 1 AND da.audit_status = 1
AND dept.name = #{department}
AND (d.name LIKE CONCAT('%', #{keyword}, '%') OR da.specialty LIKE CONCAT('%', #{keyword}, '%'))
